#!/bin/bash\nset -euo pipefail\n\necho "Deploying Agentic Flow Discord Bot with PM2..."\n\nPROJECT_DIR="$(cd "$(dirname "$0")/../agentic-flow-core" && pwd)"\n\ncd "$PROJECT_DIR"\n\n# Install dependencies\nnpm ci\n\n# Build\nnpm run build\n\n# Stop existing bot\nnpx pm2 delete af-discord-bot || true\n\n# Start bot\nnpx pm2 start "node dist/src/discord/bot.js" --name af-discord-bot\n\n# Save PM2 config\nnpx pm2 save\n\necho "✅ Discord Bot deployed successfully!"\necho "Logs: npx pm2 logs af-discord-bot"\necho "Status: npx pm2 status af-discord-bot"\necho "Restart: npx pm2 restart af-discord-bot"\necho "Stop: npx pm2 stop af-discord-bot"